const fs = require('fs');
const path = require('path');

class ProblemsService {
  constructor() {
    this.problemsFilePath = path.join(__dirname, '../../data/problems.json');
    this.problemsData = null;
    this.loadProblemsData();
  }

  loadProblemsData() {
    const rawData = fs.readFileSync(this.problemsFilePath, 'utf-8');
    this.problemsData = JSON.parse(rawData);
  }

  async getProblemById(problemId) {
    // Find problem by id
    const problem = this.problemsData.find(p => p.id === problemId);
    if (!problem) {
      const error = new Error(`Problem with id ${problemId} not found`);
      error.status = 404;
      throw error;
    }

    // Aggregate component statistics
    const componentStats = {
      languages: {},
      statusCounts: {},
      maxPoints: 0
    };

    if (Array.isArray(problem.components)) {
      for (const comp of problem.components) {
        // Aggregate languages counts
        if (comp.languages && typeof comp.languages === 'object') {
          for (const [lang, count] of Object.entries(comp.languages)) {
            componentStats.languages[lang] = (componentStats.languages[lang] || 0) + count;
          }
        }

        // Aggregate status counts
        if (comp.statusCounts && typeof comp.statusCounts === 'object') {
          for (const [status, count] of Object.entries(comp.statusCounts)) {
            componentStats.statusCounts[status] = (componentStats.statusCounts[status] || 0) + count;
          }
        }

        // Track max points
        if (typeof comp.maxPoints === 'number' && comp.maxPoints > componentStats.maxPoints) {
          componentStats.maxPoints = comp.maxPoints;
        }
      }
    }

    return {
      ...problem,
      componentStats
    };
  }
}

module.exports = new ProblemsService();
